// Slack Signature Verification + Event-Typ-Klassifikation
const crypto = require('crypto');

const signingSecret = $env.SLACK_SIGNING_SECRET;
if (!signingSecret) {
  return [{ json: { valid: false, reason: 'SLACK_SIGNING_SECRET nicht gesetzt' } }];
}

const input = $input.first();
const headers = input.json.headers || {};
const timestamp = headers['x-slack-request-timestamp'];
const slackSignature = headers['x-slack-signature'];

// Raw Body aus dem binary-Feld holen (rawBody: true im Webhook-Node)
const rawBodyBase64 = input.binary?.data?.data;
const rawBody = rawBodyBase64
  ? Buffer.from(rawBodyBase64, 'base64').toString('utf8')
  : '';

if (!rawBody || !timestamp || !slackSignature) {
  return [{ json: { valid: false, reason: 'Fehlende Headers oder Body' } }];
}

// Replay-Attack-Schutz: Requests älter als 5 Minuten ablehnen
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) {
  return [{ json: { valid: false, reason: 'Timestamp zu alt' } }];
}

// HMAC-SHA256 berechnen und timing-safe vergleichen
const baseString = `v0:${timestamp}:${rawBody}`;
const expectedSig = 'v0=' + crypto
  .createHmac('sha256', signingSecret)
  .update(baseString)
  .digest('hex');

const sigA = Buffer.from(expectedSig);
const sigB = Buffer.from(slackSignature);
const valid = sigA.length === sigB.length && crypto.timingSafeEqual(sigA, sigB);

if (!valid) {
  return [{ json: { valid: false, reason: 'Invalid signature' } }];
}

// Body parsen und Event klassifizieren
let body;
try {
  body = JSON.parse(rawBody);
} catch (e) {
  return [{ json: { valid: false, reason: 'Body ist kein gültiges JSON' } }];
}

// URL-Verification (einmalig beim Event-Subscriptions-Setup in Slack)
if (body.type === 'url_verification') {
  return [{ json: { valid: true, respondType: 'challenge', challenge: body.challenge } }];
}

// Event-Callback
if (body.type === 'event_callback' && body.event) {
  const event = body.event;

  // Bot-eigene Nachrichten ignorieren (Endlosschleife vermeiden)
  if (event.bot_id || event.subtype === 'bot_message') {
    return [{ json: { valid: true, respondType: 'ignore' } }];
  }

  const isAppMention = event.type === 'app_mention';
  const isIm = event.type === 'message' && event.channel_type === 'im';

  if (!isAppMention && !isIm) {
    return [{ json: { valid: true, respondType: 'ignore' } }];
  }

  // Frage-Text bereinigen (@mention entfernen)
  const cleanText = (event.text || '').replace(/<@[A-Z0-9]+>\s*/g, '').trim();

  return [{
    json: {
      valid: true,
      respondType: 'process',
      event: {
        user: event.user,
        channel: event.channel,
        channel_type: event.channel_type,
        ts: event.ts,
        thread_ts: event.thread_ts || null,
        text: cleanText,
        isIm,
      },
    },
  }];
}

return [{ json: { valid: true, respondType: 'ignore' } }];

// Thread-History laden (falls Thread) + User-Whitelist prüfen
const event = $('Signatur + Event prüfen').item.json.event;
const botToken = $env.SLACK_BOT_TOKEN;
const allowedRaw = $env.SLACK_ALLOWED_USERS || '';
const allowed = allowedRaw.split(',').map(s => s.trim()).filter(Boolean);

// Whitelist-Check
if (!allowed.includes(event.user)) {
  return [{
    json: {
      authorized: false,
      event,
      errorMessage: ':no_entry: Sorry, dafür bin ich nicht berechtigt.',
    },
  }];
}

// Thread-History holen falls wir in einem Thread antworten
let threadMessages = [];
if (event.thread_ts && botToken) {
  try {
    const url = `https://slack.com/api/conversations.replies?channel=${encodeURIComponent(event.channel)}&ts=${encodeURIComponent(event.thread_ts)}&limit=50`;
    const response = await fetch(url, {
      headers: { Authorization: `Bearer ${botToken}` },
    });
    const data = await response.json();
    if (data.ok) {
      threadMessages = data.messages || [];
    }
  } catch (e) {
    // Fetch fehlgeschlagen — mit leerer History weiter
    threadMessages = [];
  }
}

return [{
  json: {
    authorized: true,
    event,
    threadMessages,
  },
}];

// Alle Reports aus DB + Kontext für Claude-Prompt aufbereiten
const reportRows = $input.all().map(i => i.json);
const contextOutput = $('Kontext + Whitelist').item.json;
const event = contextOutput.event;
const threadMessages = contextOutput.threadMessages || [];

// Fall: Noch keine Reports in der DB
if (reportRows.length === 0 || (reportRows.length === 1 && !reportRows[0].platform)) {
  return [{
    json: {
      emptyDb: true,
      channel: event.channel,
      thread_ts: event.thread_ts || event.ts,
      isIm: event.isIm,
      errorMessage: ':warning: Noch keine Reports in der Datenbank. Der erste Wochenbericht wird Sonntag 09:00 automatisch erstellt.',
    },
  }];
}

// Reports pro Plattform gruppieren
const reportsByPlatform = reportRows.reduce((acc, r) => {
  if (!r.platform) return acc;
  if (!acc[r.platform]) acc[r.platform] = [];
  acc[r.platform].push(r);
  return acc;
}, {});

// Thread-History formatieren (ohne die aktuelle Nachricht)
const currentTs = event.ts;
const threadContext = threadMessages
  .filter(m => m.ts !== currentTs)
  .map(m => {
    const role = m.bot_id ? 'assistant' : 'user';
    const text = (m.text || '').replace(/<@[A-Z0-9]+>\s*/g, '').trim();
    return { role, content: text };
  })
  .filter(m => m.content.length > 0);

// System-Prompt
const availablePlatforms = Object.keys(reportsByPlatform);
const platformList = availablePlatforms
  .map(p => {
    const rs = reportsByPlatform[p];
    const earliest = rs[rs.length - 1].week_start;
    const latest = rs[0].week_start;
    return `- ${p}: ${rs.length} Wochen-Reports (von ${earliest} bis ${latest})`;
  })
  .join('\n');

const systemPrompt = `Du bist ein Performance-Marketing-Analyst für TheurerTrucks 2GO (Car-Sharing für Pferdetransporter in Deutschland).

Geschäftskontext:
- Einziger Carsharing-Anbieter für Pferdetransporter in Deutschland
- Nur EIN Fahrzeugtyp: STX Pferdetransporter auf Renault-Master-Basis, unter 3,5t, Führerschein Klasse B
- Preise: Ab 165 €/Tag (brutto), 150 km frei, Mehrkilometer 0,46 €/km
- Zielgruppe: Pferdebesitzer (90% weiblich, Ø 37 Jahre) ohne eigenen Transporter
- Conversion-Ziel: Registrierung auf fleetster-Plattform
- Ziel-CPA: unter 25 €/Registrierung

Verfügbare Daten (Wochen-Reports):
${platformList}

Jeder Report enthält Raw-Daten (JSON) vom jeweiligen Script und einen bereits generierten KI-Wochenbericht.

Antwort-Regeln:
- Schreibe auf Deutsch
- Formatiere für Slack (Slack-Markdown: *fett*, _kursiv_, • Bullet Points)
- Max 2000 Zeichen pro Antwort
- Sei konkret und actionable, nicht generisch
- Wenn die Daten für die Frage nicht reichen: klar sagen
- Emojis sparsam aber sinnvoll (:chart_with_upwards_trend:, :warning:, :white_check_mark:, :mag:, :moneybag:)`;

// User-Message mit Reports
let userMessage = 'Hier sind die verfügbaren Wochen-Reports:\n\n';
for (const [platform, reports] of Object.entries(reportsByPlatform)) {
  userMessage += `## Plattform: ${platform}\n\n`;
  for (const r of reports) {
    userMessage += `### Woche ${r.week_start} bis ${r.week_end}\n`;
    userMessage += `**KI-Bericht:**\n${r.ai_report}\n\n`;
    userMessage += `**Rohdaten (gekürzt):**\n\`\`\`json\n${JSON.stringify(r.raw_data).substring(0, 8000)}\n\`\`\`\n\n`;
  }
}
userMessage += `\n---\n\n**Aktuelle Frage:** ${event.text}`;

// Claude-Messages (Thread-History + aktuelle Frage)
const messages = [];
for (const m of threadContext) {
  messages.push({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content });
}
messages.push({ role: 'user', content: userMessage });

return [{
  json: {
    emptyDb: false,
    systemPrompt,
    messages,
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    isIm: event.isIm,
  },
}];

// Claude-Antwort + Slack-Ziel für Slack Post zusammenstellen
const claudeResponse = $input.first().json;
const promptOutput = $('Prompt bauen').item.json;

let answerText;
if (claudeResponse.content && claudeResponse.content[0]?.text) {
  answerText = claudeResponse.content[0].text;
} else if (claudeResponse.error) {
  answerText = ':rotating_light: *Claude API Fehler:* ' + (claudeResponse.error.message || JSON.stringify(claudeResponse.error));
} else {
  answerText = ':warning: Unerwartete API-Antwort von Claude.';
}

return [{
  json: {
    channel: promptOutput.channel,
    thread_ts: promptOutput.thread_ts,
    isIm: promptOutput.isIm,
    text: answerText,
  },
}];

// Fehlermeldung für unautorisierten User
const c = $input.first().json;
return [{
  json: {
    channel: c.event.channel,
    thread_ts: c.event.thread_ts || c.event.ts,
    isIm: c.event.isIm,
    text: c.errorMessage,
  },
}];
